@app.before_request
def before_request_hook():
    """Record start time and increment in-progress gauge."""
    if request.path == "/metrics":
        return
    g.start_time = time.time()
    REQUESTS_IN_PROGRESS.labels(method=request.method, endpoint=request.path).inc()


@app.after_request
def after_request_hook(response):
    """Observe latency, record counters, decrement in-progress gauge."""
    if request.path == "/metrics":
        return response

    latency = time.time() - getattr(g, "start_time", time.time())
    endpoint = request.path
    method = request.method
    status = response.status_code

    REQUEST_COUNT.labels(method=method, endpoint=endpoint, http_status=status).inc()
    REQUEST_LATENCY.labels(method=method, endpoint=endpoint).observe(latency)
    REQUEST_LATENCY_SUMMARY.labels(method=method, endpoint=endpoint).observe(latency)
    REQUESTS_IN_PROGRESS.labels(method=method, endpoint=endpoint).dec()

    resp_size = response.content_length or len(response.get_data())
    RESPONSE_SIZE.labels(method=method, endpoint=endpoint).observe(resp_size)

    return response


@app.errorhandler(Exception)
def handle_exception(exc):
    """Track unhandled exceptions."""
    endpoint = request.path
    method = request.method
    REQUEST_EXCEPTIONS.labels(
        method=method,
        endpoint=endpoint,
        exception_type=type(exc).__name__,
    ).inc()
    REQUESTS_IN_PROGRESS.labels(method=method, endpoint=endpoint).dec()
    return jsonify({"error": str(exc)}), 500


