def simulate_db_query(query_type="select"):
    duration = random.uniform(0.002, 0.15)
    time.sleep(duration)
    DB_QUERY_DURATION.labels(query_type=query_type).observe(duration)


def simulate_cache_lookup(cache_name="redis"):
    hit = random.random() < 0.8
    if hit:
        CACHE_HITS.labels(cache_name=cache_name).inc()
    else:
        CACHE_MISSES.labels(cache_name=cache_name).inc()
    return hit


def simulate_external_api(service="payment-gateway"):
    start = time.time()
    duration = random.uniform(0.01, 0.5)
    time.sleep(duration)
    success = random.random() < 0.95
    status = "success" if success else "error"
    EXTERNAL_API_CALLS.labels(service=service, status=status).inc()
    EXTERNAL_API_LATENCY.labels(service=service).observe(time.time() - start)
    return success


