def background_metrics_simulator():
    """Periodically update gauge-style business metrics to mimic real traffic."""
    categories = ["electronics", "clothing", "food", "books"]
    for cat in categories:
        ITEMS_IN_INVENTORY.labels(product_category=cat).set(random.randint(50, 500))

    while True:
        ACTIVE_USERS.set(random.randint(80, 350))
        for cat in categories:
            delta = random.randint(-5, 10)
            ITEMS_IN_INVENTORY.labels(product_category=cat).inc(delta)
        time.sleep(15)


_bg_thread = threading.Thread(target=background_metrics_simulator, daemon=True)
_bg_thread.start()


