def user_signup():
    sources = ["organic", "google", "facebook", "referral", "direct"]
    source = random.choice(sources)
    simulate_db_query("insert")
    USER_SIGNUP_COUNT.labels(referral_source=source).inc()
    return jsonify({"status": "created", "referral_source": source}), 201


@app.route("/api/orders", methods=["POST"])
def place_order():
    categories = ["electronics", "clothing", "food", "books"]
    category = random.choice(categories)
    value = round(random.uniform(5.0, 2000.0), 2)

    simulate_cache_lookup("product-cache")
    simulate_db_query("insert")
    payment_ok = simulate_external_api("payment-gateway")

    ORDERS_PLACED.labels(product_category=category).inc()
    ORDER_VALUE.labels(product_category=category).observe(value)

    if not payment_ok:
        return jsonify({"status": "payment_failed", "category": category, "value": value}), 502

    # decrement inventory
    ITEMS_IN_INVENTORY.labels(product_category=category).dec()

    return jsonify({"status": "placed", "category": category, "value": value}), 201


